sql:
SELECT gender, COUNT(*) AS number_of_politicians
FROM politicians
GROUP BY gender;

SELECT city
FROM birthplaces
WHERE birthplace_id = (SELECT birthplace FROM politicians WHERE politician_id = 0);

SELECT summary, biography
FROM politician_profiles
WHERE politician_id = 0;

SELECT COUNT(*) 
  FROM politician_roles 
  WHERE role_description = 'City Council Member';

SELECT COUNT(*) 
FROM politician_categories 
WHERE category_name = 'Retailer';
